import React, { useState, useEffect } from "react";
import LoginForm from "./LoginForm"; // chắc chắn LoginForm.js tồn tại

// Logo component
function Logo() {
  return (
    <div className="bg-blue-400 w-screen min-h-screen flex flex-col items-center justify-center">
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/uwa83iuw_expires_30_days.png"
        alt="Logo VASCO"
        className="w-[300px] h-[300px] object-contain"
      />
      <h1 className="text-4xl font-bold text-white mt-6">VASCO</h1>
      <p className="text-white text-lg mt-2">
        Kết nối - Học tập - Giải trí - Sáng tạo
      </p>
      <p className="text-white text-sm mt-4">By: KBKHC</p>
    </div>
  );
}

// App chính
export default function App() {
  const [showLogin, setShowLogin] = useState(false);

  // Tự động chuyển từ logo sang login sau 2 giây
  useEffect(() => {
    const timer = setTimeout(() => {
      setShowLogin(true);
    }, 3000); // 2000ms = 2 giây

    return () => clearTimeout(timer); // dọn dẹp timer
  }, []);

  return (
    <div>
      {showLogin ? <LoginForm /> : <Logo />}
    </div>
  );
}
